/**
 * Audit Trail — mock data and event recording.
 *
 * Records sensitive actions performed by staff members so programs can
 * demonstrate compliance and investigate access issues.
 *
 * Actions covered (per requirements):
 *  - injury_status_changed        (AC #2: records actor, timestamp, player, old, new)
 *  - readiness_override_created
 *  - private_note_accessed
 *  - dossier_published
 *  - parent_visibility_changed
 *  - assignment_created
 *  - user_invited
 *  - access_request_submitted     (generated by PermissionGate on deny+request)
 *  - access_request_approved
 *  - staff_role_changed
 *
 * AUDIT_EVENTS is module-level mutable — recordAuditEvent() appends at runtime.
 */

import type { StaffRole, PermissionAction } from "@/lib/permissions";

/* ─── Action types ────────────────────────────────────────────────────────── */

export type AuditAction =
  | "injury_status_changed"
  | "readiness_override_created"
  | "private_note_accessed"
  | "dossier_published"
  | "parent_visibility_changed"
  | "assignment_created"
  | "user_invited"
  | "access_request_submitted"
  | "access_request_approved"
  | "access_denied"
  | "staff_role_changed"
  | "player_profile_viewed";

export const AUDIT_ACTION_LABEL: Record<AuditAction, string> = {
  injury_status_changed:       "Injury status changed",
  readiness_override_created:  "Readiness override created",
  private_note_accessed:       "Private note accessed",
  dossier_published:           "Dossier published",
  parent_visibility_changed:   "Parent visibility changed",
  assignment_created:          "Assignment created",
  user_invited:                "User invited",
  access_request_submitted:    "Access request submitted",
  access_request_approved:     "Access request approved",
  access_denied:               "Access denied",
  staff_role_changed:          "Staff role changed",
  player_profile_viewed:       "Player profile viewed",
};

export const AUDIT_ACTION_SEVERITY: Record<AuditAction, "info" | "warning" | "critical"> = {
  injury_status_changed:       "warning",
  readiness_override_created:  "warning",
  private_note_accessed:       "critical",
  dossier_published:           "warning",
  parent_visibility_changed:   "warning",
  assignment_created:          "info",
  user_invited:                "warning",
  access_request_submitted:    "info",
  access_request_approved:     "warning",
  access_denied:               "critical",
  staff_role_changed:          "critical",
  player_profile_viewed:       "info",
};

/* ─── Event shape ─────────────────────────────────────────────────────────── */

export type AuditTargetType = "player" | "staff" | "dossier" | "note" | "assignment" | "system";

export interface AuditEvent {
  id: string;
  action: AuditAction;
  /** Who performed the action */
  actorId: string;
  actorName: string;
  actorRole: StaffRole;
  /** ISO timestamp */
  timestamp: string;
  programId?: string;
  /** What was acted upon */
  targetType?: AuditTargetType;
  targetId?: string;
  targetName?: string;
  /**
   * For state-change events — the value before the action.
   * Required for AC #2 (injury_status_changed).
   */
  oldValue?: string;
  /**
   * For state-change events — the value after the action.
   * Required for AC #2 (injury_status_changed).
   */
  newValue?: string;
  /** Free-form key/value pairs for extra context */
  metadata?: Record<string, string>;
  /** Populated for access_denied / access_request_submitted events */
  blockedAction?: PermissionAction;
  /** Synthetic flag — events generated by the system, not a human */
  systemGenerated?: boolean;
}

