/* ─── Counter for runtime-generated IDs ──────────────────────────────────── */

let _counter = AUDIT_EVENTS.length + 1;

/* ─── Record function ────────────────────────────────────────────────────── */

/**
 * Append a new audit event to the module-level log.
 * Call at the point of each sensitive action.
 *
 * AC #2: When an athletic trainer updates injury status, this records
 * actorId, actorName, actorRole, timestamp, targetId, targetName,
 * oldValue, and newValue.
 */
export function recordAuditEvent(
  event: Omit<AuditEvent, "id" | "timestamp">,
): AuditEvent {
  const full: AuditEvent = {
    ...event,
    id: `ae_${String(_counter++).padStart(3, "0")}`,
    timestamp: new Date().toISOString(),
  };
  AUDIT_EVENTS.push(full);
  return full;
}

/* ─── Query helpers ──────────────────────────────────────────────────────── */

export function getAuditEventsForPlayer(playerId: string): AuditEvent[] {
  return AUDIT_EVENTS.filter((e) => e.targetId === playerId);
}

export function getAuditEventsForActor(actorId: string): AuditEvent[] {
  return AUDIT_EVENTS.filter((e) => e.actorId === actorId);
}

export function getAuditEventsByAction(action: AuditAction): AuditEvent[] {
  return AUDIT_EVENTS.filter((e) => e.action === action);
}

export function getRecentAuditEvents(limit = 20): AuditEvent[] {
  return [...AUDIT_EVENTS]
    .sort((a, b) => b.timestamp.localeCompare(a.timestamp))
    .slice(0, limit);
}

